import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import type { InvoiceTotalsInput } from '../utils/orderLines';
import { useLocation, useNavigate, useParams } from 'react-router-dom';
import { dispatchAppToast, scrollToValidationTarget } from '@linm-soft-org/linm-web-common-components';
import {
  FormMode,
  effectiveFormMode,
  initialFormMode,
  isEditingMode,
  isViewMode,
  useFormFieldLock,
  shouldStartFormInEditMode,
  withFormEditModeSearch,
  withoutFormEditModeSearch,
} from '../components/form';
import type { FormNavigateEditIntent } from '../components/form';
import { useAppDispatch } from '../store/hooks';
import { bhService } from '../services/bh/bhService';
import type {
  InvoiceDto,
  InvoiceLineDto,
  InvoicePaymentLineDto,
  LinkedCashReceiptSummaryDto,
} from '../services/bh/models';
import { resolveFmLegacyCodeDisplay } from '../utils/fmLegacyCodeDisplay';
import { toDateOnlyInputValue, localInputToISOWithOffset } from '../utils/dateUtils';
import { getApiErrorMessage } from '../utils/getApiErrorMessage';
import { customerFieldHandlers, loadCustomerDisplay } from '../utils/customerField';
import {
  applyHeaderDiscountToLines,
  emptyInvoiceLine,
  hasLineDiscount,
  invoiceLinesTotal,
  normalizeInvoiceLines,
  recalcInvoiceLine,
} from '../utils/orderLines';
import { needsHeaderDiscountClearConfirm } from '../utils/lineDiscountPatch';
import { useSalesFormProcessingLevel } from './useSalesFormProcessingLevel';
import { useUnsavedChangesGuard } from './useUnsavedChangesGuard';
import { useVoucherListActions } from './useVoucherListActions';
import type { DocumentPostingStatus } from '../services/bh/ledgerModels';
import { canViewVoucherLedgerFromForm } from '../utils/voucherListRowActions';
import { openCrossMfePath } from '../utils/openCrossMfePath';
import {
  VOUCHER_COPY_STATE_KEY,
  VOUCHER_COPY_SOURCE_CODE_KEY,
  VOUCHER_SEARCH_RESULT_IDS_KEY,
} from '../components/voucher/voucherFormConstants';
import { salesDocumentTypes, erpDocumentHistoryClient } from '../config/documentHistoryClients';
import {
  resolveVoucherViewModeHint,
  buildVoucherToolbarDisabledReasons,
  isSalesInvoiceLocked,
} from '../utils/invoiceProcessingLevelDisplay';
import {
  validateInvoiceFields,
  validateInvoiceHeaderField,
  validateInvoiceLineField,
  applyInlineValidationMessage,
  collectBannerMessages,
  scrollToFirstInvoiceFieldError,
  type InvoiceFieldErrors,
  type InvoiceLineFieldErrors,
  type InvoiceLineFieldKey,
} from '../utils/invoiceFieldValidation';
import df from '../styles/documentForm.module.css';

const TEST_ID = 'hoa-don';
const INIT_FORM = 'create-sales-invoice';

type FormSnapshot = {
  invoiceDate: string;
  taxCode: string;
  description: string;
  lines: InvoiceLineDto[];
  useHeaderDiscount: boolean;
  headerDiscountAmount: number;
  headerDiscountAllocation: 'quantity' | 'amount';
  varianceAmount: number;
  processingLevel: string;
};

function buildSnapshot(state: FormSnapshot): string {
  return JSON.stringify(state);
}

/** Original stashed footer totals from server */
type StoredFooterTotals = {
  productTotal: number;
  taxAmount: number;
  total: number;
  discountAmount: number;
  varianceAmount: number;
};

function footerTotalsFromDto(inv: InvoiceDto): StoredFooterTotals {
  return {
    productTotal: inv.subTotal,
    taxAmount: inv.taxAmount,
    total: inv.totalAmount,
    discountAmount: inv.headerDiscountAmount ?? 0,
    varianceAmount: inv.varianceAmount ?? 0,
  };
}

function linesForSave(
  lines: InvoiceLineDto[],
  useHeaderDiscount: boolean,
  headerDiscountAmount: number,
  headerDiscountAllocation: 'quantity' | 'amount',
): InvoiceLineDto[] {
  if (useHeaderDiscount && headerDiscountAmount > 0 && !hasLineDiscount(lines)) {
    return applyHeaderDiscountToLines(lines, headerDiscountAmount, headerDiscountAllocation);
  }
  return normalizeInvoiceLines(lines);
}

export function useHoaDonFormPage() {
  const { id } = useParams<{ id: string }>();
  const isNew = !id;
  const navigate = useNavigate();
  const location = useLocation();
  const dispatch = useAppDispatch();
  const { canCreate, canUpdate, canViewLedger } = useVoucherListActions(INIT_FORM);
  const [postingStatus, setPostingStatus] = useState<DocumentPostingStatus>('None');
  const [showLedgerModal, setShowLedgerModal] = useState(false);
  const {
    processingLevel,
    setProcessingLevel,
    processingLevelOptions,
  } = useSalesFormProcessingLevel(isNew ? INIT_FORM : 'edit-sales-invoice');

  const [formMode, setFormMode] = useState<FormMode>(() => initialFormMode(isNew));
  const toolbarMode = effectiveFormMode(isNew, formMode);

  const [status, setStatus] = useState('Draft');
  const [invoiceDate, setInvoiceDate] = useState(() => toDateOnlyInputValue(new Date().toISOString()));
  const [invoiceCode, setInvoiceCode] = useState('');
  const [customerId, setCustomerId] = useState('');
  const [customerCode, setCustomerCode] = useState('');
  const [customerName, setCustomerName] = useState('');
  const [taxCode, setTaxCode] = useState('');
  const [description, setDescription] = useState('');
  const [shiftName, setShiftName] = useState('');
  const [cashierName, setCashierName] = useState('');
  const [legacyCode, setLegacyCode] = useState('');
  const [lines, setLines] = useState<InvoiceLineDto[]>([emptyInvoiceLine()]);
  const [useHeaderDiscount, setUseHeaderDiscount] = useState(false);
  const [headerDiscountAmount, setHeaderDiscountAmount] = useState(0);
  const [headerDiscountAllocation, setHeaderDiscountAllocation] = useState<'quantity' | 'amount'>('amount');
  const [varianceAmount, setVarianceAmount] = useState(0);
  const varianceTouchedRef = useRef(false);
  const [showVarianceConfirm, setShowVarianceConfirm] = useState(false);
  const [showHeaderDiscountClearConfirm, setShowHeaderDiscountClearConfirm] = useState(false);
  const pendingLineDiscountPatchRef = useRef<{ idx: number; prevLine: InvoiceLineDto } | null>(null);
  const [loading, setLoading] = useState(isNew ? false : true);
  const [saving, setSaving] = useState(false);
  const [deleting, setDeleting] = useState(false);
  const [headerExpanded, setHeaderExpanded] = useState(true);
  const [payments, setPayments] = useState<InvoicePaymentLineDto[]>([]);
  const [linkedReceipts, setLinkedReceipts] = useState<LinkedCashReceiptSummaryDto[]>([]);
  const [showLinkedReceiptSlideout, setShowLinkedReceiptSlideout] = useState(false);
  const [savedSnapshot, setSavedSnapshot] = useState('');
  const [storedFooterTotals, setStoredFooterTotals] = useState<StoredFooterTotals>({
    productTotal: 0,
    taxAmount: 0,
    total: 0,
    discountAmount: 0,
    varianceAmount: 0,
  });
  const savedStateRef = useRef<FormSnapshot | null>(null);
  const searchCacheRef = useRef<Map<string, InvoiceDto>>(new Map());
  const [searchResultIds, setSearchResultIds] = useState<string[]>([]);
  const [showSearchSlideout, setShowSearchSlideout] = useState(false);
  const [showPrintModal, setShowPrintModal] = useState(false);
  const [showHistoryModal, setShowHistoryModal] = useState(false);
  const [printing, setPrinting] = useState(false);
  const [showDeleteModal, setShowDeleteModal] = useState(false);

  // Pattern B validation (2026-07)
  const validationAttemptedRef = useRef(false);
  const [fieldErrors, setFieldErrors] = useState<InvoiceFieldErrors>({});
  const [generalErrors, setGeneralErrors] = useState<string[]>([]);
  const [validationErrors, setValidationErrors] = useState<string[]>([]);
  const [bannerExpanded, setBannerExpanded] = useState(true);
  const [bannerClosed, setBannerClosed] = useState(false);
  const validationBannerId = 'hoa-don-validation-banner';
  const tid = (suffix: string) => `${TEST_ID}-${suffix}`;

  // Pattern B per-field re-validation (parity PT/PC)
  const patchInvoiceFieldError = useCallback((key: keyof InvoiceFieldErrors, value: string) => {
    const rawMsg = validateInvoiceHeaderField(key, value, 'Khách hàng');
    const msg = applyInlineValidationMessage(validationAttemptedRef.current, rawMsg);
    setFieldErrors(prev => {
      const next = { ...prev };
      if (msg) {
        (next as Record<string, string | undefined>)[key] = msg;
      } else {
        delete (next as Record<string, string | undefined>)[key];
      }
      return next;
    });
  }, []);

  // Pattern B per-line re-validation (parity PT/PC)
  const patchInvoiceLineFieldError = useCallback((rowIdx: number, key: string, value: string | number | undefined, currentMaterialCode?: string) => {
    const rawMsg = validateInvoiceLineField(rowIdx, key as InvoiceLineFieldKey, value, currentMaterialCode);
    const msg = applyInlineValidationMessage(validationAttemptedRef.current, rawMsg);
    setFieldErrors(prev => {
      const next = { ...prev };
      const nextLines = next.lineErrors ? { ...next.lineErrors } : {};
      const current = nextLines[rowIdx] ? { ...nextLines[rowIdx] } : {};
      if (msg) {
        (current as Record<string, string | undefined>)[key] = msg;
        nextLines[rowIdx] = current as InvoiceLineFieldErrors;
      } else {
        delete (current as Record<string, string | undefined>)[key];
        if (Object.keys(current).length > 0) {
          nextLines[rowIdx] = current as InvoiceLineFieldErrors;
        } else {
          delete nextLines[rowIdx];
        }
      }
      next.lineErrors = Object.keys(nextLines).length > 0 ? nextLines : undefined;
      return next;
    });
  }, []);

  const copySourceRef = useRef<string | null>(null);
  const [copySourceVoucherCode, setCopySourceVoucherCode] = useState<string | null>(null);
  const applyCopySnapshotRef = useRef(false);

  // Copy hydration — if user navigated here from Copy
  useEffect(() => {
    if (!isNew) return;
    const copyState = (location.state as Record<string, unknown>)?.[VOUCHER_COPY_STATE_KEY];
    const sourceCode = (location.state as Record<string, unknown>)?.[VOUCHER_COPY_SOURCE_CODE_KEY] as string | undefined;
    if (copyState && sourceCode) {
      const snap = copyState as FormSnapshot;
      setInvoiceDate(snap.invoiceDate);
      setTaxCode(snap.taxCode);
      setDescription(snap.description);
      setLines(snap.lines.map(l => ({ ...l })));
      setUseHeaderDiscount(snap.useHeaderDiscount);
      setHeaderDiscountAmount(snap.headerDiscountAmount);
      setHeaderDiscountAllocation(snap.headerDiscountAllocation);
      setVarianceAmount(snap.varianceAmount);
      setProcessingLevel(snap.processingLevel);
      copySourceRef.current = sourceCode;
      setCopySourceVoucherCode(sourceCode);
      applyCopySnapshotRef.current = true;
    }
  }, [isNew, location.state]);

  // Search nav — hydrate from location state
  useEffect(() => {
    if (isNew) return;
    const ids = (location.state as Record<string, unknown>)?.[VOUCHER_SEARCH_RESULT_IDS_KEY];
    if (Array.isArray(ids)) {
      setSearchResultIds(ids as string[]);
    }
  }, [isNew, location.state]);

  const documentHistoryType = 'SalesInvoice';
  const hasSearchNav = !isNew && searchResultIds.length > 0 && searchResultIds.includes(id ?? '');
  const searchNavIndex = hasSearchNav ? searchResultIds.indexOf(id ?? '') : -1;

  const isStatusLocked = !isNew && isSalesInvoiceLocked(status);
  const showEditDelete = !isNew && canUpdate && !isSalesInvoiceLocked(status);

  const viewModeHint = resolveVoucherViewModeHint({
    formMode: toolbarMode,
    isNew,
    status,
    processingLevel,
    canEditWhenView: showEditDelete,
  });

  const toolbarDisabledReasons = buildVoucherToolbarDisabledReasons({
    isNew,
    status,
    isStatusLocked,
  });

  const fieldLock = useFormFieldLock({
    formMode: toolbarMode,
    isStatusLocked,
    styles: {
      viewReadOnlySection: df.viewReadOnlySection,
      searchViewOnly: df.searchViewOnly,
      embeddedSearch: df.lineMaterialSearch,
    },
  });

  const customerHandlers = useMemo(
    () => customerFieldHandlers(setCustomerId, setCustomerCode, setCustomerName),
    [],
  );

  const liveTotals = useMemo(
    () => invoiceLinesTotal({
      lines,
      useHeaderDiscount,
      headerDiscountAmount,
      headerDiscountAllocation,
      varianceAmount,
    } satisfies InvoiceTotalsInput),
    [lines, useHeaderDiscount, headerDiscountAmount, headerDiscountAllocation, varianceAmount],
  );

  useEffect(() => {
    if (isViewMode(toolbarMode) || varianceTouchedRef.current) return;
    if (liveTotals.suggestedVariance !== varianceAmount) {
      setVarianceAmount(liveTotals.suggestedVariance);
    }
  }, [liveTotals.suggestedVariance, toolbarMode, varianceAmount]);

  const currentSnapshot = buildSnapshot({
    invoiceDate,
    taxCode,
    description,
    lines,
    useHeaderDiscount,
    headerDiscountAmount,
    headerDiscountAllocation,
    varianceAmount,
    processingLevel,
  });
  const isDirty = isEditingMode(toolbarMode) && currentSnapshot !== savedSnapshot;

  const { guardedAction, showUnsavedModal, confirmLeave, cancelLeave } = useUnsavedChangesGuard(
    isDirty,
    isEditingMode(toolbarMode),
  );

  const applyDto = useCallback(async (inv: InvoiceDto) => {
    setInvoiceDate(toDateOnlyInputValue(inv.invoiceDate));
    setInvoiceCode(inv.code);
    setStatus(inv.status);
    setCustomerId(inv.customerId);
    setTaxCode(inv.taxCode ?? '');
    setDescription(inv.description ?? '');
    setShiftName(inv.shiftName ?? '');
    setCashierName(inv.cashierName ?? '');
    setLegacyCode(resolveFmLegacyCodeDisplay(inv.code, inv.legacyCode) ?? '');
    setUseHeaderDiscount(inv.useHeaderDiscount ?? false);
    setHeaderDiscountAmount(inv.headerDiscountAmount ?? 0);
    setHeaderDiscountAllocation(inv.headerDiscountAllocation ?? 'amount');
    varianceTouchedRef.current = false;
    setVarianceAmount(inv.varianceAmount ?? 0);
    setProcessingLevel(inv.processingLevel ?? '');
    const mappedLines = inv.lines?.length
      ? inv.lines.map(l => ({
          id: l.id,
          materialCode: l.materialCode,
          materialName: l.materialName ?? '',
          unitCode: l.unitCode,
          quantity: l.quantity,
          unitPrice: l.unitPrice,
          discountRate: l.discountRate ?? 0,
          discountAmount: l.discountAmount ?? 0,
          amount: l.amount,
          taxRate: l.taxRate,
          taxAmount: l.taxAmount,
        }))
      : [emptyInvoiceLine()];
    setLines(mappedLines);
    setStoredFooterTotals(footerTotalsFromDto(inv));
    setPayments(inv.payments ?? []);
    setLinkedReceipts(inv.linkedReceipts ?? []);
    const display = await loadCustomerDisplay(inv.customerId, inv.customerName);
    setCustomerCode(display.code);
    setCustomerName(display.name);
    const snap: FormSnapshot = {
      invoiceDate: toDateOnlyInputValue(inv.invoiceDate),
      taxCode: inv.taxCode ?? '',
      description: inv.description ?? '',
      lines: mappedLines,
      useHeaderDiscount: inv.useHeaderDiscount ?? false,
      headerDiscountAmount: inv.headerDiscountAmount ?? 0,
      headerDiscountAllocation: inv.headerDiscountAllocation ?? 'amount',
      varianceAmount: inv.varianceAmount ?? 0,
      processingLevel: inv.processingLevel ?? '',
    };
    savedStateRef.current = snap;
    setSavedSnapshot(buildSnapshot(snap));
  }, [processingLevel]);

  useEffect(() => {
    if (!isNew || savedSnapshot) return;
    const snap: FormSnapshot = {
      invoiceDate,
      taxCode,
      description,
      lines,
      useHeaderDiscount,
      headerDiscountAmount,
      headerDiscountAllocation,
      varianceAmount,
      processingLevel,
    };
    savedStateRef.current = snap;
    setSavedSnapshot(buildSnapshot(snap));
  }, [
    isNew, savedSnapshot, invoiceDate, taxCode, description, lines,
    useHeaderDiscount, headerDiscountAmount, headerDiscountAllocation, varianceAmount, processingLevel,
  ]);

  // Sync validation errors → banner (parity PT/PC)
  useEffect(() => {
    const allErrors = [...collectBannerMessages(fieldErrors), ...generalErrors];
    setValidationErrors(allErrors);
  }, [fieldErrors, generalErrors]);

  // startInEditMode — from URL ?mode=edit or location.state
  const editIntentAppliedForIdRef = useRef<string | null>(null);
  useEffect(() => {
    if (isNew) {
      editIntentAppliedForIdRef.current = null;
      return;
    }
    const hasEditIntent = shouldStartFormInEditMode(
      location.search,
      location.state as FormNavigateEditIntent | null,
    );
    if (!hasEditIntent) {
      if (editIntentAppliedForIdRef.current === id) {
        editIntentAppliedForIdRef.current = null;
      }
      return;
    }
    if (editIntentAppliedForIdRef.current === id) return;
    editIntentAppliedForIdRef.current = id ?? null;
    if (showEditDelete) {
      setFormMode(FormMode.Edit);
    }
  }, [isNew, id, location.search, location.state, showEditDelete]);

  useEffect(() => {
    if (!id) return;
    let cancelled = false;
    const t = setTimeout(() => {
      setLoading(true);
      bhService.getInvoice(id)
        .then(async inv => {
          if (cancelled) return;
          await applyDto(inv);
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, { message: getApiErrorMessage(err, 'Lỗi tải hóa đơn'), type: 'error' });
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [id, dispatch, applyDto]);

  useEffect(() => {
    if (!id || isNew) return;
    let cancelled = false;
    bhService.getInvoicePostingStatus(id)
      .then(ps => {
        if (!cancelled) setPostingStatus(ps.postingStatus);
      })
      .catch(() => {
        if (!cancelled) setPostingStatus('None');
      });
    return () => { cancelled = true; };
  }, [id, isNew, processingLevel, status]);

  const canViewLedgerToolbar = canViewVoucherLedgerFromForm({
    isNew,
    id,
    status,
    processingLevel,
    postingStatus,
    canViewLedgerPermission: canViewLedger,
  });

  const restoreSaved = useCallback(() => {
    const snap = savedStateRef.current;
    if (!snap) return;
    setInvoiceDate(snap.invoiceDate);
    setTaxCode(snap.taxCode);
    setDescription(snap.description);
    setLines(snap.lines.map(l => ({ ...l })));
    setUseHeaderDiscount(snap.useHeaderDiscount);
    setHeaderDiscountAmount(snap.headerDiscountAmount);
    setHeaderDiscountAllocation(snap.headerDiscountAllocation);
    varianceTouchedRef.current = false;
    setVarianceAmount(snap.varianceAmount);
    setProcessingLevel(snap.processingLevel);
    setSavedSnapshot(buildSnapshot(snap));
  }, [setProcessingLevel]);

  const handleBack = useCallback(() => {
    guardedAction(() => navigate('/bh/hoa-don'));
  }, [guardedAction, navigate]);

  const handleEdit = useCallback(() => {
    if (!showEditDelete) return;
    setFormMode(FormMode.Edit);
    if (!isNew) {
      const nextSearch = withFormEditModeSearch(location.search);
      if (nextSearch !== location.search) {
        navigate(
          { pathname: location.pathname, search: nextSearch },
          { replace: true, state: location.state },
        );
      }
    }
  }, [showEditDelete, isNew, location.pathname, location.search, location.state, navigate]);

  const handleCancel = useCallback(() => {
    if (isNew) {
      guardedAction(() => navigate('/bh/hoa-don'));
      return;
    }
    restoreSaved();
    setFormMode(FormMode.View);
    setHeaderExpanded(true);
    const nextSearch = withoutFormEditModeSearch(location.search);
    if (nextSearch !== location.search) {
      navigate(
        { pathname: location.pathname, search: nextSearch },
        { replace: true, state: location.state },
      );
    }
  }, [isNew, guardedAction, navigate, restoreSaved, location.pathname, location.search, location.state]);

  const persistSave = useCallback(async () => {
    validationAttemptedRef.current = true;
    const normalized = linesForSave(
      lines,
      useHeaderDiscount,
      headerDiscountAmount,
      headerDiscountAllocation,
    );
    const payload = {
      taxCode,
      description,
      useHeaderDiscount,
      headerDiscountAmount: useHeaderDiscount ? headerDiscountAmount : 0,
      headerDiscountAllocation,
      varianceAmount,
      processingLevel,
      lines: normalized,
    };

    if (!isNew && id) {
      const updated = await bhService.updateInvoice(id, payload);
      dispatchAppToast(dispatch, { message: 'Cập nhật hóa đơn thành công', type: 'success' });
      setStoredFooterTotals(footerTotalsFromDto(updated));
      const snap: FormSnapshot = {
        invoiceDate,
        taxCode,
        description,
        lines: normalized,
        useHeaderDiscount,
        headerDiscountAmount,
        headerDiscountAllocation,
        varianceAmount,
        processingLevel,
      };
      savedStateRef.current = snap;
      setSavedSnapshot(buildSnapshot(snap));
      setFormMode(FormMode.View);
      setHeaderExpanded(true);
    } else {
      await bhService.createInvoice({
        invoiceDate: localInputToISOWithOffset(invoiceDate),
        customerId,
        ...payload,
      });
      dispatchAppToast(dispatch, { message: 'Tạo hóa đơn thành công', type: 'success' });
      navigate('/bh/hoa-don');
    }
  }, [
    lines, useHeaderDiscount, headerDiscountAmount, headerDiscountAllocation, varianceAmount,
    taxCode, description, isNew, id, dispatch, invoiceDate, customerId, processingLevel, navigate,
  ]);

  const handleSave = useCallback(async () => {
    validationAttemptedRef.current = true;
    // Pattern B validation — collect field errors + banner messages
    const { fieldErrors: nextFieldErrors, bannerMessages } = validateInvoiceFields({
      invoiceDate,
      customerId,
      requireCustomerId: true,
      customerLabel: 'Khách hàng',
      description,
      linesCount: lines.length,
      lines: lines.length > 0
        ? lines.map(l => ({ materialCode: l.materialCode, quantity: l.quantity, unitPrice: l.unitPrice }))
        : undefined,
    });
    setFieldErrors(nextFieldErrors);
    setGeneralErrors(bannerMessages);
    setBannerClosed(false);
    setBannerExpanded(true);

    if (bannerMessages.length > 0 || Object.keys(nextFieldErrors).length > 0) {
      scrollToFirstInvoiceFieldError(nextFieldErrors, tid, validationBannerId);
      return;
    }
    const normalized = linesForSave(
      lines,
      useHeaderDiscount,
      headerDiscountAmount,
      headerDiscountAllocation,
    );
    if (Math.abs(varianceAmount) > 0) {
      setShowVarianceConfirm(true);
      return;
    }
    setSaving(true);
    try {
      await persistSave();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, { message: getApiErrorMessage(err, 'Lưu thất bại'), type: 'error' });
    } finally {
      setSaving(false);
    }
  }, [customerId, lines, useHeaderDiscount, headerDiscountAmount, headerDiscountAllocation, varianceAmount, dispatch, persistSave]);

  const confirmVarianceSave = useCallback(async () => {
    validationAttemptedRef.current = true;
    setShowVarianceConfirm(false);
    const { bannerMessages: validationMessages, fieldErrors: afterFieldErrors } = validateInvoiceFields({
      invoiceDate,
      customerId,
      requireCustomerId: true,
      customerLabel: 'Khách hàng',
      description,
      linesCount: lines.length,
      lines: lines.length > 0
        ? lines.map(l => ({ materialCode: l.materialCode, quantity: l.quantity, unitPrice: l.unitPrice }))
        : undefined,
    });
    setFieldErrors(afterFieldErrors);
    if (validationMessages.length > 0 || Object.keys(afterFieldErrors).length > 0) {
      setGeneralErrors(validationMessages);
      setBannerClosed(false);
      setBannerExpanded(true);
      scrollToFirstInvoiceFieldError(afterFieldErrors, tid, validationBannerId);
      return;
    }
    setSaving(true);
    try {
      await persistSave();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, { message: getApiErrorMessage(err, 'Lưu thất bại'), type: 'error' });
    } finally {
      setSaving(false);
    }
  }, [customerId, lines, dispatch, persistSave]);

  const handleVarianceAmountChange = useCallback((value: number) => {
    varianceTouchedRef.current = true;
    setVarianceAmount(value);
  }, []);

  const handleUseHeaderDiscountChange = useCallback((checked: boolean) => {
    varianceTouchedRef.current = false;
    setUseHeaderDiscount(checked);
    if (!checked) {
      setHeaderDiscountAmount(0);
      setVarianceAmount(0);
    }
  }, []);

  const handleHeaderDiscountAmountChange = useCallback((value: number) => {
    varianceTouchedRef.current = false;
    setHeaderDiscountAmount(value);
  }, []);

  const handleHeaderDiscountAllocationChange = useCallback((value: 'quantity' | 'amount') => {
    varianceTouchedRef.current = false;
    setHeaderDiscountAllocation(value);
  }, []);

  const clearHeaderDiscountState = useCallback(() => {
    varianceTouchedRef.current = false;
    setUseHeaderDiscount(false);
    setHeaderDiscountAmount(0);
    setVarianceAmount(0);
  }, []);

  const patchLine = useCallback((idx: number, patch: Partial<InvoiceLineDto>) => {
    const line = lines[idx];
    if (!line) return;

    const needsConfirm = needsHeaderDiscountClearConfirm(
      patch,
      line,
      useHeaderDiscount,
      headerDiscountAmount,
    );

    if (needsConfirm) {
      pendingLineDiscountPatchRef.current = { idx, prevLine: { ...line } };
      setShowHeaderDiscountClearConfirm(true);
    }

    setLines(prev => prev.map((l, i) => (i === idx ? recalcInvoiceLine({ ...l, ...patch }) : l)));
  }, [lines, useHeaderDiscount, headerDiscountAmount]);

  const confirmHeaderDiscountClear = useCallback(() => {
    clearHeaderDiscountState();
    setShowHeaderDiscountClearConfirm(false);
    pendingLineDiscountPatchRef.current = null;
  }, [clearHeaderDiscountState]);

  const cancelHeaderDiscountClear = useCallback(() => {
    const pending = pendingLineDiscountPatchRef.current;
    setShowHeaderDiscountClearConfirm(false);
    pendingLineDiscountPatchRef.current = null;
    if (!pending) return;
    setLines(prev => prev.map((l, i) =>
      (i === pending.idx ? recalcInvoiceLine({ ...pending.prevLine }) : l)));
  }, []);

  const handleDelete = useCallback(async () => {
    if (!id || !showEditDelete) return;
    setDeleting(true);
    try {
      await bhService.deleteInvoice(id);
      dispatchAppToast(dispatch, { message: 'Đã xóa hóa đơn', type: 'success' });
      navigate('/bh/hoa-don');
    } catch (err: unknown) {
      dispatchAppToast(dispatch, { message: getApiErrorMessage(err, 'Xóa thất bại'), type: 'error' });
    } finally {
      setDeleting(false);
    }
  }, [id, showEditDelete, dispatch, navigate]);

  const totals = isViewMode(toolbarMode)
    ? {
        productTotal: storedFooterTotals.productTotal,
        subTotal: storedFooterTotals.productTotal,
        taxAmount: storedFooterTotals.taxAmount,
        total: storedFooterTotals.total,
        lineDiscountTotal: 0,
        headerDiscountTotal: storedFooterTotals.discountAmount,
        varianceAmount: storedFooterTotals.varianceAmount,
        suggestedVariance: 0,
      }
    : liveTotals;

  const canEditLines = isEditingMode(toolbarMode) && !fieldLock.isReadOnly;
  const lineDiscountActive = hasLineDiscount(lines);
  const discountDisplayTotal = isViewMode(toolbarMode)
    ? storedFooterTotals.discountAmount
    : liveTotals.lineDiscountTotal + liveTotals.headerDiscountTotal;

  const displayVariance = isViewMode(toolbarMode)
    ? storedFooterTotals.varianceAmount
    : varianceAmount;

  const canViewLinkedReceipts = !isNew && isViewMode(toolbarMode) && linkedReceipts.length > 0;
  const receiptLinkHint = isNew
    ? 'Tạo phiếu thu tương ứng trên Kế toán → Phiếu thu sau khi lưu hóa đơn.'
    : isEditingMode(toolbarMode)
      ? linkedReceipts.length > 0
        ? 'Sửa phiếu thu tương ứng — mở «Xem phiếu thu» (chế độ xem) hoặc Kế toán → Phiếu thu.'
        : 'Tạo/Sửa phiếu thu tương ứng trên Kế toán → Phiếu thu.'
      : null;

  // 1 hint duy nhất — merge receipt context vào edit-hint message (không ghi đè copy-hint)
  const editingHint = isEditingMode(toolbarMode) && receiptLinkHint
    ? `Đang ${isNew ? 'tạo mới' : 'chỉnh sửa'} — ${receiptLinkHint}`
    : undefined;

  const handleOpenLinkedReceipt = useCallback((receipt: LinkedCashReceiptSummaryDto) => {
    openCrossMfePath(receipt.viewUrl || `/kt/pt/${receipt.id}`, navigate);
    setShowLinkedReceiptSlideout(false);
  }, [navigate]);

  return {
    TEST_ID,
    isNew,
    toolbarMode,
    isViewMode: isViewMode(toolbarMode),
    isEditing: isEditingMode(toolbarMode),
    fieldLock,
    viewModeHint,
    toolbarDisabledReasons,
    loading,
    saving,
    deleting,
    headerExpanded,
    setHeaderExpanded,
    invoiceDate,
    setInvoiceDate,
    invoiceCode,
    customerId,
    customerCode,
    customerName,
    customerHandlers,
    taxCode,
    setTaxCode,
    description,
    setDescription,
    shiftName,
    cashierName,
    legacyCode,
    lines,
    setLines,
    patchLine,
    useHeaderDiscount,
    setUseHeaderDiscount: handleUseHeaderDiscountChange,
    headerDiscountAmount,
    setHeaderDiscountAmount: handleHeaderDiscountAmountChange,
    headerDiscountAllocation,
    setHeaderDiscountAllocation: handleHeaderDiscountAllocationChange,
    varianceAmount: displayVariance,
    setVarianceAmount: handleVarianceAmountChange,
    processingLevel,
    setProcessingLevel,
    processingLevelOptions,
    totals,
    discountDisplayTotal,
    lineDiscountActive,
    canEditLines,
    showEditDelete,
    canCreate,
    canUpdate,
    isStatusLocked,
    handleBack,
    handleEdit,
    handleCancel,
    handleSave,
    handleDelete,
    showUnsavedModal,
    confirmLeave,
    cancelLeave,
    showVarianceConfirm,
    setShowVarianceConfirm,
    confirmVarianceSave,
    showHeaderDiscountClearConfirm,
    confirmHeaderDiscountClear,
    cancelHeaderDiscountClear,
    navigate,
    canViewLedger: canViewLedgerToolbar,
    showLedgerModal,
    setShowLedgerModal,
    postingStatus,
    invoiceId: id,
    payments,
    linkedReceipts,
    canViewLinkedReceipts,
    showLinkedReceiptSlideout,
    setShowLinkedReceiptSlideout,
    handleOpenLinkedReceipt,
    receiptLinkHint,
    editingHint,
    // Validation banner (Pattern B)
    validationErrors,
    fieldErrors,
    setFieldErrors,
    patchInvoiceFieldError,
    lineErrors: fieldErrors.lineErrors,
    patchInvoiceLineFieldError,
    bannerExpanded,
    setBannerExpanded,
    bannerClosed,
    setBannerClosed,
    validationBannerId,
    tid,
    showDeleteModal,
    setShowDeleteModal,

    // Copy
    copySourceVoucherCode,
    handleCopy: useCallback(() => {
      if (isNew) return;
      guardedAction(() => {
        const snap: FormSnapshot = {
          invoiceDate,
          taxCode,
          description,
          lines,
          useHeaderDiscount,
          headerDiscountAmount,
          headerDiscountAllocation,
          varianceAmount,
          processingLevel,
        };
        navigate('/bh/hoa-don/them', {
          state: {
            [VOUCHER_COPY_STATE_KEY]: snap,
            [VOUCHER_COPY_SOURCE_CODE_KEY]: invoiceCode,
          },
        });
      });
    }, [isNew, guardedAction, navigate, invoiceDate, taxCode, description, lines,
        useHeaderDiscount, headerDiscountAmount, headerDiscountAllocation, varianceAmount, processingLevel, invoiceCode]),

    // Print
    showPrintModal,
    setShowPrintModal,
    printing,
    handlePrint: useCallback(async (templateId: string) => {
      setPrinting(true);
      try {
        dispatchAppToast(dispatch, { message: `In chứng từ (mẫu: ${templateId}) — chức năng sẽ được triển khai`, type: 'success' });
      } finally {
        setPrinting(false);
        setShowPrintModal(false);
      }
    }, [dispatch]),

    // History
    showHistoryModal,
    setShowHistoryModal,
    documentHistoryType,
    documentHistoryClient: erpDocumentHistoryClient,

    // Search
    showSearchSlideout,
    setShowSearchSlideout,
    hasSearchNav,
    searchNavIndex,
    searchResultIds,
    handleOpenFromSearch: useCallback((id: string, resultIds: string[], _items: InvoiceDto[]) => {
      navigate(`/bh/hoa-don/${id}`, {
        state: { [VOUCHER_SEARCH_RESULT_IDS_KEY]: resultIds },
      });
    }, [navigate]),
    navigateToSearchId: useCallback((targetId: string) => {
      guardedAction(() => navigate(`/bh/hoa-don/${targetId}`, {
        state: { [VOUCHER_SEARCH_RESULT_IDS_KEY]: searchResultIds },
      }));
    }, [guardedAction, navigate, searchResultIds]),
  };
}
